  // map for spelling (longest-first applied via array order)
  function applyRoad(text) {
    var s = String(text == null ? "" : text);
    // 1) spelling fix (literal)
    for (var i = 0; i < SPELLING.length; i += 1) {
      if (s.indexOf(SPELLING[i][0]) !== -1) s = s.split(SPELLING[i][0]).join(SPELLING[i][1]);
    }
    // 2) regex replace (units / ทล. / ม. / จ. etc.)
    for (var j = 0; j < REGEX_REPLACE.length; j += 1) {
      s = s.replace(REGEX_REPLACE[j][0], REGEX_REPLACE[j][1]);
    }
    // 3) abbreviations (long-form -> short)
    for (var k = 0; k < ABBREV.length; k += 1) {
      if (s.indexOf(ABBREV[k][0]) !== -1) s = s.split(ABBREV[k][0]).join(ABBREV[k][1]);
    }
    return s.replace(/[ \t]+/g, " ").trim();
  }

  return { applyRoad: applyRoad, SPELLING: SPELLING, REGEX_REPLACE: REGEX_REPLACE, ABBREV: ABBREV };
